import com.google.gson.GsonBuilder;

public class GsonBuilderTest {

  @Test
  public void testSetLenient() throws Exception {
    GsonBuilder builder = new GsonBuilder();
    // Initially lenient should be default (false)
    Field lenientField = GsonBuilder.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);
    assertFalse(lenientField.getBoolean(builder));

    // Call setLenient and verify it returns the same builder instance
    GsonBuilder returned = builder.setLenient();
    assertSame(builder, returned);

    // Verify lenient field is set to true
    assertTrue(lenientField.getBoolean(builder));
  }
}
